def create_server(
    host: str = "0.0.0.0",
    port: int = 50051,
    max_workers: int = None,
    use_so_reuseport: bool = True,
) -> grpc.Server:
    """Create and configure the gRPC server optimized for high throughput."""
    
    # Use CPU count based workers if not specified
    if max_workers is None:
        import multiprocessing
        max_workers = max(multiprocessing.cpu_count() * 2, 8)
    
    # Thread pool for handling RPCs
    thread_pool = futures.ThreadPoolExecutor(
        max_workers=max_workers,
        thread_name_prefix="grpc-worker",
    )
    
    # Server options optimized for high throughput and low latency
    # No message size limits, no rate limiting
    server_options = [
        # Remove default message size limits - unlimited
        ("grpc.max_send_message_length", -1),
        ("grpc.max_receive_message_length", -1),
        
        # HTTP/2 settings for maximum throughput
        ("grpc.http2.max_pings_without_data", 0),
        ("grpc.keepalive_time_ms", 10000),
        ("grpc.keepalive_timeout_ms", 5000),
        ("grpc.keepalive_permit_without_calls", 1),
        ("grpc.http2.min_time_between_pings_ms", 5000),
        ("grpc.http2.min_ping_interval_without_data_ms", 5000),
        
        # Large window sizes for high throughput streaming
        ("grpc.http2.max_frame_size", 16777215),  # ~16MB frames
        ("grpc.http2.stream_lookahead_bytes", 67108864),  # 64MB lookahead
        
        # Connection settings
        ("grpc.max_concurrent_streams", 1000),
        ("grpc.max_connection_idle_ms", 0),  # No idle timeout
        ("grpc.max_connection_age_ms", 0),  # No age limit
        
        # Enable SO_REUSEPORT for multi-process servers
        ("grpc.so_reuseport", int(use_so_reuseport)),
        
        # Compression support
        ("grpc.default_compression_algorithm", 0),  # No default compression for lowest latency
        ("grpc.default_compression_level", 0),
        
        # TCP settings
        ("grpc.tcp_tx_buf_size", 4 * 1024 * 1024),  # 4MB TX buffer
        ("grpc.tcp_rx_buf_size", 4 * 1024 * 1024),  # 4MB RX buffer
    ]
    
    server = grpc.server(
        thread_pool,
        options=server_options,
        maximum_concurrent_rpcs=None,  # No limit on concurrent RPCs
        compression=grpc.Compression.NoCompression,  # Lowest latency
    )
    
    servicer = DataStreamServicer()
    datastream_pb2_grpc.add_DataStreamServiceServicer_to_server(servicer, server)
    
    # Bind to address
    address = f"{host}:{port}"
    server.add_insecure_port(address)
    
    logger.info(f"Server configured: {address}, workers={max_workers}")
    logger.info(f"Server options: unlimited message size, unlimited concurrent RPCs, "
                f"unlimited streams")
    
    return server, servicer


def serve(host="0.0.0.0", port=50051, max_workers=None):
    """Start the gRPC server."""
    server, servicer = create_server(host, port, max_workers)
    server.start()
    
    logger.info(f"DataStream gRPC server started on {host}:{port}")
    
    # Graceful shutdown handling
    shutdown_event = False
    
    def handle_shutdown(signum, frame):
        nonlocal shutdown_event
        if not shutdown_event:
            shutdown_event = True
            logger.info(f"Received signal {signum}, initiating graceful shutdown...")
            stats = servicer.metrics.get_stats()
            logger.info(f"Final stats: {stats}")
            # Grace period for in-flight RPCs
            server.stop(grace=5)
    
    signal.signal(signal.SIGINT, handle_shutdown)
    signal.signal(signal.SIGTERM, handle_shutdown)
    
    # Log stats periodically
    try:
        while not shutdown_event:
            time.sleep(30)
            if not shutdown_event:
                stats = servicer.metrics.get_stats()
                logger.info(f"Server stats: {stats}")
    except KeyboardInterrupt:
        handle_shutdown(signal.SIGINT, None)
    
    server.wait_for_termination()
    logger.info("Server shut down cleanly")


