class DataStreamClient:
    """Test client for the DataStream service."""
    
    def __init__(self, target: str = "localhost:50051"):
        channel_options = [
            ("grpc.max_send_message_length", -1),
            ("grpc.max_receive_message_length", -1),
            ("grpc.keepalive_time_ms", 10000),
            ("grpc.keepalive_timeout_ms", 5000),
            ("grpc.keepalive_permit_without_calls", 1),
            ("grpc.http2.max_frame_size", 16777215),
            ("grpc.default_compression_algorithm", 0),
        ]
        self.channel = grpc.insecure_channel(target, options=channel_options)
        self.stub = datastream_pb2_grpc.DataStreamServiceStub(self.channel)
    
    def process_data(self, payload: bytes, data_type=datastream_pb2.TELEMETRY, source="test"):
        request = datastream_pb2.DataRequest(
            request_id=f"req-{time.time_ns()}",
            source=source,
            timestamp=int(time.time() * 1000),
            payload=payload,
            data_type=data_type,
        )
        return self.stub.ProcessData(request)
    
    def stream_results(self, payload: bytes, data_type=datastream_pb2.TELEMETRY):
        request = datastream_pb2.DataRequest(
            request_id=f"req-{time.time_ns()}",
            source="test",
            timestamp=int(time.time() * 1000),
            payload=payload,
            data_type=data_type,
        )
        responses = []
        for response in self.stub.StreamResults(request):
            responses.append(response)
        return responses
    
    def ingest_stream(self, payloads, data_type=datastream_pb2.TELEMETRY):
        def request_generator():
            for i, payload in enumerate(payloads):
                yield datastream_pb2.DataRequest(
                    request_id=f"req-{time.time_ns()}-{i}",
                    source="test",
                    timestamp=int(time.time() * 1000),
                    payload=payload if isinstance(payload, bytes) else payload.encode(),
                    data_type=data_type,
                )
        return self.stub.IngestStream(request_generator())
    
    def bidirectional_stream(self, payloads, data_type=datastream_pb2.TELEMETRY):
        def request_generator():
            for i, payload in enumerate(payloads):
                yield datastream_pb2.DataRequest(
                    request_id=f"req-{time.time_ns()}-{i}",
                    source="test",
                    timestamp=int(time.time() * 1000),
                    payload=payload if isinstance(payload, bytes) else payload.encode(),
                    data_type=data_type,
                )
        
        responses = []
        for response in self.stub.BidirectionalStream(request_generator()):
            responses.append(response)
        return responses
    
    def health_check(self):
        request = datastream_pb2.HealthRequest(service_name="datastream")
        return self.stub.HealthCheck(request)
    
    def close(self):
        self.channel.close()


def run_benchmark(target="localhost:50051", num_requests=10000, payload_size=1024):
    """Run a simple throughput benchmark."""
    client = DataStreamClient(target)
    
    # Health check
    health = client.health_check()
    logger.info(f"Server health: {health.status}")
    
    payload = os.urandom(payload_size)
    
    # Unary benchmark
    logger.info(f"Running unary benchmark: {num_requests} requests, {payload_size}B payload...")
    start = time.time()
    for i in range(num_requests):
        client.process_data(payload)
    elapsed = time.time() - start
    rps = num_requests / elapsed
    logger.info(f"Unary: {rps:.0f} req/s, {elapsed:.2f}s total, "
                f"{elapsed/num_requests*1000:.2f}ms avg latency")
    
    # Client streaming benchmark
    num_stream = min(num_requests, 50000)
    logger.info(f"Running client streaming benchmark: {num_stream} messages...")
    payloads = [payload] * num_stream
    start = time.time()
    response = client.ingest_stream(payloads)
    elapsed = time.time() - start
    mps = num_stream / elapsed
    logger.info(f"Client streaming: {mps:.0f} msg/s, {elapsed:.2f}s total, "
                f"response: {response.message}")
    
    # Bidirectional streaming benchmark
    num_bidi = min(num_requests, 10000)
    logger.info(f"Running bidirectional streaming benchmark: {num_bidi} messages...")
    payloads = [payload] * num_bidi
    start = time.time()
    responses = client.bidirectional_stream(payloads)
    elapsed = time.time() - start
    mps = num_bidi / elapsed
    logger.info(f"Bidirectional streaming: {mps:.0f} msg/s, {elapsed:.2f}s total, "
                f"{len(responses)} responses")
    
    # Final health check
    health = client.health_check()
    logger.info(f"Server stats - requests: {health.requests_processed}, "
                f"avg latency: {health.avg_latency_ms:.2f}ms, "
                f"uptime: {health.uptime_seconds}s")
    
    client.close()


